import { readFileSync } from 'node:fs';
const img = readFileSync('packages/agent-core/src/tools/builtin/media/generate-image.ts','utf8');
const vid = readFileSync('packages/agent-core/src/tools/builtin/media/generate-video.ts','utf8');
const tools = readFileSync('packages/agent-core/src/agent/tool/index.ts','utf8');
const footer = readFileSync('apps/liora/src/tui/components/chrome/footer.ts','utf8');
const fails=[];
if (!img.includes('OPENAI_API_KEY')) fails.push('img-openai');
if (!img.includes('GOOGLE_API_KEY')) fails.push('img-google');
if (!img.includes('isGenerateImageAvailable')) fails.push('img-avail');
if (!img.includes("args.size ?? '1024x1024'")) fails.push('img-size-default');
if (!img.includes("args.provider ?? 'auto'")) fails.push('img-provider-auto');
if (!vid.includes('isGenerateVideoAvailable')) fails.push('vid-avail');
if (!vid.includes("args.aspect_ratio ?? '16:9'")) fails.push('vid-aspect');
if (!vid.includes('args.duration_seconds ?? 5')) fails.push('vid-duration');
if (!tools.includes("shouldCreateBuiltin('GenerateImage')")) fails.push('reg-img');
if (!tools.includes("shouldCreateBuiltin('GenerateVideo')")) fails.push('reg-vid');
if (!footer.includes('formatMediaFooterBadge')) fails.push('footer-media');
if (fails.length) { console.error(fails.join(',')); process.exit(1);} console.log('media-zero-config-source-ok');
